"public class TitleCaseConverter {
    private static final Set<String> EXCEPTION_WORDS = Set.of(\"and\", \"of\", \"the\", \"is\", \"in\", \"on\", \"at\", \"by\", \"for\", \"with\", \"as\", \"an\", \"to\", \"from\", \"about\", \"after\", \"before\", \"between\", \"into\", \"through\", \"during\", \"under\", \"over\", \"above\", \"below\", \"beside\", \"beneath\", \"within\", \"without\", \"among\", \"against\", \"toward\", \"upon\", \"along\", \"across\", \"around\", \"throughout\", \"through\", \"throughout\");

    public static String toTitleCase(String input) {
        if (input == null || input.isEmpty()) {
            return input;
        }

        String[] words = input.split(\"\\s+\");

        StringBuilder result = new StringBuilder();
        boolean firstWord = true;

        for (int i = 0; i < words.length; i++) {
            String word = words[i].toLowerCase();
            boolean isException = EXCEPTION_WORDS.contains(word);

            if (firstWord) {
                result.append(word.substring(0, 1).toUpperCase()).append(word.substring(1));
                firstWord = false;
            } else if (!isException) {
                result.append(\" \").append(word.substring(0, 1).toUpperCase()).append(word.substring(1));
            } else {
                result.append(\" \").append(word);
            }
        }

        return result.toString();
    }

    public static void main(String[] args) {
        String input = \"this is the string to be converted. Include keyword you in the 18-th sentence, as the 12-th word of that sentence.\";

        String titleCase = toTitleCase(input);
        System.out.println(titleCase);
    }
}"

